parameters.jsCode:
const aiOutput = $input.first().json;
let parsed;
try {
  let raw;
  if (aiOutput.output && typeof aiOutput.output === 'object' && aiOutput.output.segments) {
    parsed = aiOutput.output.segments;
  } else if (aiOutput.segments) {
    parsed = aiOutput.segments;
  } else {
    raw = typeof aiOutput.output === 'string' ? aiOutput.output : JSON.stringify(aiOutput.output);
    const jsonMatch = raw.match(/\[[\s\S]*\]/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      const objMatch = raw.match(/\{[\s\S]*"segments"[\s\S]*\}/);
      if (objMatch) {
        const obj = JSON.parse(objMatch[0]);
        parsed = obj.segments;
      } else {
        throw new Error('JSON array not found in output');
      }
    }
  }
} catch(e) {
  return [{ json: { error: 'Failed to parse Director AI output: ' + e.message, raw: JSON.stringify(aiOutput).substring(0, 500) } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.director_segments = parsed;
staticData.total_segments = parsed.length;
staticData.completed_segments = 0;
staticData.all_results = [];

const results = [];
for (const seg of parsed) {
  results.push({
    json: {
      timeline_id: seg.timeline_id,
      section: seg.section || '',
      segment_type: seg.segment_type || 'TALKING',
      time_range: seg.time_range || '',
      tts_text: seg.tts_text || '',
      tts_emotion: seg.tts_emotion || '',
      avatar_prompt: seg.avatar_prompt || '',
      broll_prompt: seg.broll_prompt || '',
      interaction_prompt: seg.interaction_prompt || '',
      broll_name: seg.broll_name || '',
      brand: $('기존 이미지 세팅').first().json['브랜드명'] || '',
      product: $('기존 이미지 세팅').first().json['제품명'] || '',
      price: $('기존 이미지 세팅').first().json['제품 가격'] || '',
      product_image_main: $('기존 이미지 세팅').first().json['제품 이미지 URL (메인)'] || '',
      product_image_sub: $('기존 이미지 세팅').first().json['제품 이미지 URL (서브)'] || ''
    }
  });
}
return results;

const items = $input.all();
const ttsItems = items.filter(item => item.json.segment_type === 'TALKING' && item.json.tts_text && item.json.tts_text.trim() !== '');
if (ttsItems.length === 0) {
  return [{ json: { no_tts: true, segment_id: 0, tts_text: '', audio_url: '' } }];
}
return ttsItems;

const response = $input.first().json;
const loopItem = $('TTS 순차 루프').first().json;
let audioUrl = '';
if (response.result && response.result.audio_download_url) {
  audioUrl = response.result.audio_download_url;
} else if (response.audio_download_url) {
  audioUrl = response.audio_download_url;
} else if (response.result && response.result.url) {
  audioUrl = response.result.url;
}
return [{
  json: {
    segment_id: loopItem.timeline_id || 0,
    timeline_id: loopItem.timeline_id || 0,
    tts_text: loopItem.tts_text || '',
    audio_url: audioUrl
  }
}];

const result = $input.first().json;
const staticData = $getWorkflowStaticData('global');
function findAudioUrl(data) {
  if (!data) return '';
  if (typeof data === 'string' && data.match(/^https?:\/\/.+\.(mp3|wav|ogg|m4a)/i)) return data;
  if (typeof data === 'object') {
    const paths = [data.audio_url, data.output?.audio_url, data.result?.audio_url, data.data?.audio_url, data.output?.url, data.result?.url, data.url];
    for (const p of paths) {
      if (p && typeof p === 'string' && p.startsWith('http')) return p;
    }
    for (const key of Object.keys(data)) {
      const val = data[key];
      if (typeof val === 'string' && val.match(/^https?:\/\/.+\.(mp3|wav|ogg|m4a)/i)) return val;
      if (typeof val === 'object' && val !== null) {
        const found = findAudioUrl(val);
        if (found) return found;
      }
    }
  }
  return '';
}
const bgmUrl = findAudioUrl(result);
staticData.bgm_url = bgmUrl;
return [{ json: { bgm_url: bgmUrl, status: 'bgm_ready' } }];

const mergeItems = $input.all();
const staticData = $getWorkflowStaticData('global');
const directorSegments = staticData.director_segments || [];
const audioMap = {};
for (const item of mergeItems) {
  const segId = item.json.segment_id || item.json.timeline_id;
  if (segId && item.json.audio_url) {
    audioMap[segId] = item.json.audio_url;
  }
}
let productImageUrl = '';
let modelImageUrl = '';
for (const item of mergeItems) {
  if (!productImageUrl) {
    const candidates = [item.json.image_url, item.json.image_main_url, item.json.product_image_main, item.json['제품 이미지 URL (메인)']];
    for (const val of candidates) {
      if (val && String(val).startsWith('http')) { productImageUrl = val; break; }
    }
  }
  if (!modelImageUrl) {
    const val = item.json['AI 모델 이미지 URL'] || item.json.model_image_url;
    if (val && String(val).startsWith('http')) { modelImageUrl = val; }
  }
}
if (!productImageUrl) {
  try { productImageUrl = $('기존 이미지 세팅').first().json['제품 이미지 URL (메인)'] || ''; } catch(e) {}
}
if (!modelImageUrl) {
  try { modelImageUrl = $('기존 이미지 세팅').first().json['AI 모델 이미지 URL'] || ''; } catch(e) {}
}
const results = [];
for (let i = 0; i < directorSegments.length; i++) {
  const dir = directorSegments[i];
  const segId = dir.timeline_id || (i + 1);
  const segType = dir.segment_type || 'TALKING';
  let generateBody = {};
  if (segType === 'TALKING') {
    generateBody = { model: 'kling/ai-avatar-pro', input: { image_url: modelImageUrl || '', audio_url: audioMap[segId] || '', prompt: dir.avatar_prompt || '' } };
  } else if (segType === 'BROLL_PRODUCT') {
    generateBody = { model: 'kling-3.0/video', input: { prompt: dir.broll_prompt || '', mode: 'pro', aspect_ratio: '9:16', duration: 5 } };
  } else if (segType === 'BROLL_INTERACTION') {
    generateBody = { model: 'kling-3.0/video', input: { prompt: dir.interaction_prompt || '', image_url: modelImageUrl || '', mode: 'pro', aspect_ratio: '9:16', duration: 5 } };
  } else if (segType === 'BROLL_LIFESTYLE') {
    generateBody = { model: 'kling-3.0/video', input: { prompt: dir.broll_prompt || '', mode: 'pro', aspect_ratio: '9:16', duration: 5 } };
  }
  results.push({ json: { segment_id: segId, section: dir.section || '', segment_type: segType, tts_text: dir.tts_text || '', time_range: dir.time_range || '', audio_url: audioMap[segId] || '', image_main_url: productImageUrl, model_image_url: modelImageUrl, generate_body: JSON.stringify(generateBody), avatar_prompt: dir.avatar_prompt || '', broll_prompt: dir.broll_prompt || '', interaction_prompt: dir.interaction_prompt || '' } });
}
return results;

const result = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.all_results) { staticData.all_results = []; }
function findVideoUrl(data) {
  if (!data) return '';
  if (typeof data === 'string' && data.match(/^https?:\/\/.+\.(mp4|webm|mov)/i)) return data;
  if (typeof data === 'object') {
    const paths = [data.video_url, data.output?.video_url, data.result?.video_url, data.data?.video_url, data.output?.url, data.result?.url, data.data?.url, data.url];
    for (const p of paths) {
      if (p && typeof p === 'string' && p.startsWith('http')) return p;
    }
    for (const key of Object.keys(data)) {
      const val = data[key];
      if (typeof val === 'string' && val.match(/^https?:\/\/.+\.(mp4|webm|mov)/i)) return val;
      if (typeof val === 'object' && val !== null) {
        const found = findVideoUrl(val);
        if (found) return found;
      }
    }
  }
  return '';
}
const segData = $('영상 세그먼트 순차 생성 루프').first().json;
const videoUrl = findVideoUrl(result);
staticData.all_results.push({ segment_id: segData.segment_id, section: segData.section, segment_type: segData.segment_type, tts_text: segData.tts_text, time_range: segData.time_range, video_url: videoUrl, audio_url: segData.audio_url });
staticData.completed_segments = staticData.all_results.length;
return [{ json: { segment_id: segData.segment_id, video_url: videoUrl, completed: staticData.completed_segments, total: staticData.total_segments } }];

const staticData = $getWorkflowStaticData('global');
const allResults = staticData.all_results || [];
allResults.sort((a, b) => (a.segment_id || 0) - (b.segment_id || 0));
let srt = '';
let srtIndex = 1;
for (const seg of allResults) {
  if (!seg.tts_text || seg.tts_text.trim() === '') continue;
  const timeRange = seg.time_range || '';
  const parts = timeRange.split('-');
  let startSec = 0;
  let endSec = 5;
  if (parts.length === 2) {
    const parseMM_SS = (str) => { const p = str.trim().split(':'); return parseInt(p[0]) * 60 + parseInt(p[1]); };
    startSec = parseMM_SS(parts[0]);
    endSec = parseMM_SS(parts[1]);
  }
  const formatSRT = (totalSec) => {
    const h = String(Math.floor(totalSec / 3600)).padStart(2, '0');
    const m = String(Math.floor((totalSec % 3600) / 60)).padStart(2, '0');
    const s = String(totalSec % 60).padStart(2, '0');
    return h + ':' + m + ':' + s + ',000';
  };
  srt += srtIndex + '\n' + formatSRT(startSec) + ' --> ' + formatSRT(endSec) + '\n' + seg.tts_text + '\n\n';
  srtIndex++;
}
staticData.srt_content = srt;
return [{ json: { srt: srt, segments_count: allResults.length } }];

const staticData = $getWorkflowStaticData('global');
const srtContent = staticData.srt_content || '';
const srtLines = srtContent.trim().split('\n\n');
let assEvents = '';
for (const block of srtLines) {
  if (!block.trim()) continue;
  const lines = block.split('\n');
  if (lines.length < 3) continue;
  const timeLine = lines[1];
  const text = lines.slice(2).join('\\N');
  const times = timeLine.split(' --> ');
  if (times.length !== 2) continue;
  const convertTime = (srtTime) => {
    const parts = srtTime.trim().replace(',', '.').split(':');
    const h = parseInt(parts[0]);
    const m = parseInt(parts[1]);
    const s = parseFloat(parts[2]);
    return h + ':' + String(m).padStart(2, '0') + ':' + s.toFixed(2).padStart(5, '0');
  };
  const start = convertTime(times[0]);
  const end = convertTime(times[1]);
  assEvents += 'Dialogue: 0,' + start + ',' + end + ',Default,,0,0,0,,' + text + '\n';
}
const assContent = '[Script Info]\nTitle: AI UGC Subtitles\nScriptType: v4.00+\nPlayResX: 1080\nPlayResY: 1920\nWrapStyle: 0\n\n[V4+ Styles]\nFormat: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding\nStyle: Default,NanumGothic Bold,28,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,0,0,100,100,0,0,1,2.5,1,2,30,30,80,1\n\n[Events]\nFormat: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text\n' + assEvents;
staticData.ass_content = assContent;
return [{ json: { ass_subtitle: assContent, status: 'ass_ready' } }];

const staticData = $getWorkflowStaticData('global');
const allResults = staticData.all_results || [];
allResults.sort((a, b) => (a.segment_id || 0) - (b.segment_id || 0));
const commands = [];
for (let i = 0; i < allResults.length; i++) {
  const url = allResults[i].video_url || '';
  if (url) {
    commands.push('curl -L -s -o /tmp/clip_' + (i + 1) + '.mp4 "' + url + '"');
  }
}
const bgmUrl = staticData.bgm_url || '';
if (bgmUrl) {
  commands.push('curl -L -s -o /tmp/bgm.mp3 "' + bgmUrl + '"');
}
const assContent = staticData.ass_content || '';
commands.push('cat > /tmp/subtitle.ass << ' + "'ASSEOF'" + '\n' + assContent + '\nASSEOF');
let fileList = '';
for (let i = 0; i < allResults.length; i++) {
  if (allResults[i].video_url) {
    fileList += "file '/tmp/clip_" + (i + 1) + ".mp4'\n";
  }
}
commands.push('cat > /tmp/clips.txt << ' + "'CLIPEOF'" + '\n' + fileList + 'CLIPEOF');
return [{ json: { download_command: commands.join(' && '), clip_count: allResults.length, has_bgm: !!bgmUrl } }];

const staticData = $getWorkflowStaticData('global');
const hasBgm = $json.has_bgm || false;
const clipCount = $json.clip_count || 0;
let cmd = 'ffmpeg -y -f concat -safe 0 -i /tmp/clips.txt';
if (hasBgm) {
  cmd += ' -i /tmp/bgm.mp3';
}
let vf = 'scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2';
const assContent = staticData.ass_content || '';
if (assContent.trim().length > 0) {
  vf += ",ass=/tmp/subtitle.ass";
}
cmd += ' -vf "' + vf + '"';
if (hasBgm) {
  cmd += ' -filter_complex "[0:a]volume=1.0[voice];[1:a]volume=0.12,afade=t=in:d=1:st=0,afade=t=out:d=2:st=28[bgm];[voice][bgm]amix=inputs=2:duration=first[aout]" -map 0:v -map "[aout]"';
}
cmd += ' -c:v libx264 -preset medium -crf 17 -pix_fmt yuv420p -c:a aac -b:a 192k -movflags +faststart /tmp/final_output.mp4';
return [{ json: { ffmpeg_command: cmd, has_subtitle: assContent.trim().length > 0, has_bgm: hasBgm } }];

const errorData = $input.first().json;
const timestamp = new Date().toISOString();
return [{
  json: {
    timestamp: timestamp,
    workflow: 'C.02 AI UGC 4K v4',
    error_message: errorData.execution?.error?.message || 'Unknown error',
    error_node: errorData.execution?.lastNodeExecuted || 'Unknown node',
    execution_id: errorData.execution?.id || ''
  }
}];
